    if (!changed) {
        return false; // No change needed
    }

    // Build new order and update collection
    Set<E> newSet = new HashSet<E>();
    List<E> newList = new ArrayList<E>();

    for (E element : setOrder) {
        if (coll.contains(element) && newSet.add(element)) {
            // Only add if it should be retained and we haven't added it before
            newList.add(element);
        }
    }

